<?php if ( ! defined( 'ABSPATH' ) ) { exit; } if(cdb_is_yarpp_active()){ if(function_exists('yarpp_related')){ yarpp_related(); } return; } $cats=wp_get_post_categories(get_the_ID()); $q=new WP_Query(array('post_type'=>'post','posts_per_page'=>3,'post__not_in'=>array(get_the_ID()),'category__in'=>$cats)); if($q->have_posts()): ?><section class="related-posts"><h2>Posts relacionados</h2><div class="post-grid"><?php while($q->have_posts()):$q->the_post(); get_template_part('template-parts/content-card'); endwhile; ?></div></section><?php endif; wp_reset_postdata(); ?>
